def predict(inputs):
    # Camada 1
    l1 = relu([sum(i*w for i, w in zip(inputs, col)) + b for col, b in zip(list(map(list, zip(*W1))), B1)])
    # Camada 2
    l2 = relu([sum(i*w for i, w in zip(l1, col)) + b for col, b in zip(list(map(list, zip(*W2))), B2)])
    # Saída
    l3 = softmax([sum(i*w for i, w in zip(l2, col)) + b for col, b in zip(list(map(list, zip(*W3))), B3)])
    return l3



